Use greedy insertion with regret-based tie-breaking and fallback expansion for unassigned orders.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type candidate struct {
		idx     int
		delta   float64
		regret  float64
		success bool
	}
	const SEED_IDX = 0
	for jj := range oris {
		bestCand := candidate{idx: -1, delta: 1e18, regret: 0, success: false}
		secondDelta := 1e18
		candidates := make([]candidate, 0, dispatch.AssignsLen+1)
		for ii := 0; ii <= dispatch.AssignsLen; ii++ {
			costBefore := dispatch.Assigns[ii].Cost
			id := total_ship + jj
			ok := dispatch.Assigns[ii].AddShip(id, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[ii].GenRoute()
				if dispatch.Assigns[ii].Cost >= 0 {
					delta := dispatch.Assigns[ii].Cost - costBefore
					if delta < 0 {
						delta = 0
					}
					cands := candidate{idx: ii, delta: delta, regret: 0, success: true}
					candidates = append(candidates, cands)
					if delta < bestCand.delta {
						secondDelta = bestCand.delta
						bestCand = cands
					} else if delta < secondDelta {
						secondDelta = delta
					}
					dispatch.Assigns[ii].RemoveShip(id)
					dispatch.Assigns[ii].GenRoute()
					continue
				}
			}
			if !ok || dispatch.Assigns[ii].Cost < 0 {
				dispatch.Assigns[ii].RemoveShip(id)
				dispatch.Assigns[ii].GenRoute()
			}
		}
		if len(candidates) == 0 {
			fallbackIdx := SEED_IDX
			if dispatch.AssignsLen < MAXASSIGNS {
				fallbackIdx = dispatch.AssignsLen
			}
			ok := dispatch.Assigns[fallbackIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if ok {
				dispatch.Assigns[fallbackIdx].GenRoute()
				if dispatch.Assigns[fallbackIdx].Cost >= 0 {
					if fallbackIdx >= dispatch.AssignsLen {
						dispatch.AssignsLen++
					}
				} else {
					dispatch.Assigns[fallbackIdx].RemoveShip(total_ship + jj)
					dispatch.Assigns[fallbackIdx].GenRoute()
				}
			}
			continue
		}
		if secondDelta < 1e17 {
			bestCand.regret = secondDelta - bestCand.delta
		}
		selectedIdx := bestCand.idx
		if selectedIdx < 0 && len(candidates) > 0 {
			selectedIdx = candidates[0].idx
		}
		if selectedIdx >= 0 {
			dispatch.Assigns[selectedIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[selectedIdx].GenRoute()
			if selectedIdx >= dispatch.AssignsLen {
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

